import{_ as a,o as i,c as s,ag as e}from"./chunks/framework.ClpDZR9J.js";const k=JSON.parse('{"title":"HTML 基础概念","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/html/01-basic-concepts.md","filePath":"frontend/html/01-basic-concepts.md","lastUpdated":1773364959000}'),d={name:"frontend/html/01-basic-concepts.md"};function o(r,t,l,n,h,p){return i(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="html-基础概念" tabindex="-1">HTML 基础概念 <a class="header-anchor" href="#html-基础概念" aria-label="Permalink to &quot;HTML 基础概念&quot;">​</a></h1><p>HTML 基础概念相关面试题，包括浏览器内核和 DOCTYPE。</p><h2 id="浏览器内核" tabindex="-1">浏览器内核 <a class="header-anchor" href="#浏览器内核" aria-label="Permalink to &quot;浏览器内核&quot;">​</a></h2><h3 id="主流浏览器内核分类" tabindex="-1">主流浏览器内核分类 <a class="header-anchor" href="#主流浏览器内核分类" aria-label="Permalink to &quot;主流浏览器内核分类&quot;">​</a></h3><p>浏览器内核（渲染引擎）负责解析 HTML、CSS 并将内容渲染到屏幕上。</p><table tabindex="0"><thead><tr><th>内核名称</th><th>特点</th><th>代表浏览器</th></tr></thead><tbody><tr><td>Trident</td><td>微软开发，早期 IE 浏览器内核，兼容性好但更新慢</td><td>Internet Explorer（旧版）、360 安全浏览器（兼容模式）、QQ 浏览器（兼容模式）</td></tr><tr><td>Gecko</td><td>Mozilla 开发，开源且支持现代 Web 标准</td><td>Mozilla Firefox</td></tr><tr><td>WebKit</td><td>苹果基于 KHTML 开发，轻量高效，移动端占主导</td><td>Safari（桌面和 iOS）、旧版 Chrome（2013 年前）</td></tr><tr><td>Blink</td><td>Google 基于 WebKit 分支开发，性能优化强，占据桌面浏览器市场主流</td><td>Google Chrome、Microsoft Edge（2019 年后）、新版 Opera、Vivaldi、Brave、360 极速浏览器（极速模式）</td></tr><tr><td>EdgeHTML</td><td>微软为 Edge 浏览器开发，后放弃并转向 Blink</td><td>旧版 Microsoft Edge（2015-2019 年）</td></tr></tbody></table><h3 id="内核的主要职责" tabindex="-1">内核的主要职责 <a class="header-anchor" href="#内核的主要职责" aria-label="Permalink to &quot;内核的主要职责&quot;">​</a></h3><ol><li><strong>解析 HTML</strong>：将 HTML 文档解析为 DOM 树</li><li><strong>解析 CSS</strong>：解析 CSS 样式，构建 CSSOM 树</li><li><strong>渲染页面</strong>：将 DOM 树和 CSSOM 树合并为渲染树，计算布局并绘制到屏幕</li><li><strong>JavaScript 引擎</strong>：虽然 JS 引擎独立于渲染引擎，但两者紧密协作</li></ol><h3 id="常见面试问题" tabindex="-1">常见面试问题 <a class="header-anchor" href="#常见面试问题" aria-label="Permalink to &quot;常见面试问题&quot;">​</a></h3><p><strong>Q: 什么是浏览器内核？</strong></p><p>浏览器内核（Rendering Engine）是浏览器最核心的部分，负责解析网页内容并渲染显示。不同内核对网页语法的解释不同，导致同一网页在不同浏览器中显示效果可能不同。</p><p><strong>Q: 为什么 Chrome 和 Safari 曾经都用 WebKit，现在 Chrome 用 Blink？</strong></p><p>2013 年 Google 宣布从 WebKit 分支出来开发 Blink 引擎。原因是 WebKit 主要服务于 Safari，Google 需要一个更适合 Chrome 多进程架构的渲染引擎，同时减少与苹果的依赖关系。</p><p><strong>Q: 移动端浏览器内核有哪些？</strong></p><ul><li><strong>iOS 设备</strong>：WebKit（苹果政策要求，iOS 上所有浏览器包括 Chrome、Firefox、Edge 等都强制使用 WebKit）</li><li><strong>Android 设备</strong>：Blink（Chrome、Edge 等，Android 4.4 之前系统浏览器使用 WebKit）</li><li><strong>国产浏览器</strong>：多采用 Blink 内核（如 UC、QQ 浏览器）</li></ul><h2 id="doctype" tabindex="-1">DOCTYPE <a class="header-anchor" href="#doctype" aria-label="Permalink to &quot;DOCTYPE&quot;">​</a></h2><h3 id="doctype-的作用" tabindex="-1">DOCTYPE 的作用 <a class="header-anchor" href="#doctype-的作用" aria-label="Permalink to &quot;DOCTYPE 的作用&quot;">​</a></h3><p><code>&lt;!DOCTYPE&gt;</code> 声明位于 HTML 文档的最前面，是一条指令，告诉浏览器当前 HTML 文档使用的是哪个版本的 HTML 规范。</p><h3 id="doctype-的分类" tabindex="-1">DOCTYPE 的分类 <a class="header-anchor" href="#doctype-的分类" aria-label="Permalink to &quot;DOCTYPE 的分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>HTML5</td><td>简洁的声明，推荐使用</td><td><code>&lt;!DOCTYPE html&gt;</code></td></tr><tr><td>HTML 4.01 Strict</td><td>严格模式，不包含已废弃标签</td><td><code>&lt;!DOCTYPE HTML PUBLIC &quot;-//W3C//DTD HTML 4.01//EN&quot; &quot;http://www.w3.org/TR/html4/strict.dtd&quot;&gt;</code></td></tr><tr><td>HTML 4.01 Transitional</td><td>过渡模式，包含已废弃标签</td><td><code>&lt;!DOCTYPE HTML PUBLIC &quot;-//W3C//DTD HTML 4.01 Transitional//EN&quot; &quot;http://www.w3.org/TR/html4/loose.dtd&quot;&gt;</code></td></tr><tr><td>XHTML 1.0 Strict</td><td>XHTML 严格模式</td><td><code>&lt;!DOCTYPE html PUBLIC &quot;-//W3C//DTD XHTML 1.0 Strict//EN&quot; &quot;http://www.w3.org/TR/xhtml1/DTD/xhtml1-strict.dtd&quot;&gt;</code></td></tr></tbody></table><h3 id="标准模式与怪异模式" tabindex="-1">标准模式与怪异模式 <a class="header-anchor" href="#标准模式与怪异模式" aria-label="Permalink to &quot;标准模式与怪异模式&quot;">​</a></h3><p>浏览器根据 DOCTYPE 来决定以哪种模式渲染页面：</p><table tabindex="0"><thead><tr><th>模式</th><th>触发条件</th><th>特点</th></tr></thead><tbody><tr><td><strong>标准模式（Standards Mode）</strong></td><td>有正确的 DOCTYPE 声明</td><td>按照 W3C 标准渲染，各浏览器表现一致</td></tr><tr><td><strong>怪异模式（Quirks Mode）</strong></td><td>没有 DOCTYPE 或 DOCTYPE 不正确</td><td>模拟旧浏览器（如 IE6）的行为，保留兼容性但可能不符合标准。不同浏览器的怪异模式行为可能不同</td></tr></tbody></table><h3 id="常见面试问题-1" tabindex="-1">常见面试问题 <a class="header-anchor" href="#常见面试问题-1" aria-label="Permalink to &quot;常见面试问题&quot;">​</a></h3><p><strong>Q: 为什么需要 DOCTYPE 声明？</strong></p><p>DOCTYPE 声明告诉浏览器使用哪个 HTML 规范来解析和渲染页面，确保页面在不同浏览器中表现一致。如果没有 DOCTYPE，浏览器会进入怪异模式，使用旧的渲染规则，导致页面在不同浏览器中显示差异。</p><p><strong>Q: HTML5 的 DOCTYPE 为什么这么简洁？</strong></p><p>HTML5 的 DOCTYPE <code>&lt;!DOCTYPE html&gt;</code> 设计简洁，是因为：</p><ol><li>HTML5 不再基于 SGML，不需要引用 DTD</li><li>这个声明足以让浏览器进入标准模式</li><li>更易记忆和书写</li></ol><p><strong>Q: 标准模式和怪异模式有什么区别？</strong></p><ul><li><strong>标准模式</strong>：浏览器按照 W3C 规范渲染，CSS 盒模型正确，各浏览器表现一致</li><li><strong>怪异模式</strong>：浏览器模拟旧版 IE 的行为，CSS 盒模型可能是 IE 盒模型（width 包含 padding 和 border），布局可能出现问题</li></ul><p><strong>Q: 如何检测浏览器当前处于哪种模式？</strong></p><p>可以通过 <code>document.compatMode</code> 检测（基于 MDN 官方文档）：</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (document.compatMode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;CSS1Compat&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;标准模式（Standards Mode）&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (document.compatMode </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;BackCompat&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;怪异模式（Quirks Mode）&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>说明：</strong></p><ul><li><code>CSS1Compat</code>：标准模式（Standards Mode）或接近标准模式（Almost Standards Mode）</li><li><code>BackCompat</code>：怪异模式（Quirks Mode）</li></ul>`,36)])])}const g=a(d,[["render",o]]);export{k as __pageData,g as default};
